import { describe, expect, it } from 'vitest';

import {
  adist,
  admitENF,
  constantTrace,
  continuity,
  ENFMaster,
  enfRusticCertificate,
  gridRef,
  hasCutoff,
  matchedTrace,
  matches,
  otherGrid,
  splicedTrace,
  tamperFlagged,
  totalVariation,
  type Trace,
} from '../src/electrical-network-frequency';

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 1, 5, 42]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(50, 60)).toBe(10);
    expect(adist(60, 50)).toBe(10);
    expect(adist(0, 20)).toBe(20);
  });

  it('saturates at zero (Nat truncated subtraction)', () => {
    expect(adist(0, 0)).toBe(0);
    expect(Math.max(0, 4 - 9)).toBe(0);
  });
});

describe('matches (mirrors matchesB / matchedTrace_matches_grid)', () => {
  it('a varied trace matches its grid reference within tolerance 1', () => {
    expect(matches(1, matchedTrace, gridRef)).toBe(true);
  });

  it('does NOT match a well-separated grid (hard negative)', () => {
    expect(matches(1, matchedTrace, otherGrid)).toBe(false);
  });

  it('rejects on length mismatch immediately', () => {
    expect(matches(1, [50, 51], gridRef)).toBe(false);
    expect(matches(1, gridRef, [50, 51, 49])).toBe(false);
  });

  it('two empty traces trivially match', () => {
    expect(matches(0, [], [])).toBe(true);
  });

  it('a single out-of-tolerance sample fails the whole match', () => {
    const offByTwo: Trace = [50, 50, 50, 51, 49, 52];
    // index 4: |49 - 48| = 1 OK; index 5: |52 - 50| = 2 > tol 1
    expect(matches(1, offByTwo, gridRef)).toBe(false);
    expect(matches(2, offByTwo, gridRef)).toBe(true);
  });
});

describe('totalVariation / variation gate (mirrors constTrace_variation_zero)', () => {
  it('a constant trace has zero total variation', () => {
    expect(totalVariation(constantTrace)).toBe(0);
  });

  it('a drifting trace has positive total variation', () => {
    expect(totalVariation(matchedTrace)).toBeGreaterThan(0);
    expect(totalVariation(gridRef)).toBeGreaterThan(0);
  });

  it('sums successive excursion distances', () => {
    // [50,51,49] -> |50-51| + |51-49| = 1 + 2 = 3
    expect(totalVariation([50, 51, 49])).toBe(3);
  });

  it('empty / singleton traces have zero variation', () => {
    expect(totalVariation([])).toBe(0);
    expect(totalVariation([50])).toBe(0);
  });
});

describe('continuity / tamper gate (mirrors continuousB / tamperFlagged)', () => {
  it('the genuine grid reference is continuous at step bound 3', () => {
    expect(continuity(3, gridRef)).toBe(true);
    expect(tamperFlagged(3, gridRef)).toBe(false);
    expect(hasCutoff(3, gridRef)).toBe(false);
  });

  it('the spliced trace is flagged at step bound 3 (the 51 -> 70 jump)', () => {
    expect(continuity(3, splicedTrace)).toBe(false);
    expect(tamperFlagged(3, splicedTrace)).toBe(true);
    expect(hasCutoff(3, splicedTrace)).toBe(true);
  });

  it('continuity and tamperFlagged are exact duals', () => {
    for (const t of [gridRef, matchedTrace, splicedTrace, constantTrace]) {
      expect(tamperFlagged(3, t)).toBe(!continuity(3, t));
      expect(hasCutoff(3, t)).toBe(!continuity(3, t));
    }
  });
});

describe('promotion check: admitENF', () => {
  const opts = { grid: gridRef, matchTol: 1, maxStep: 3 } as const;

  it('admits a varied trace that matches its grid and is continuous', () => {
    const a = admitENF(matchedTrace, opts);
    expect(a.outcome).toBe('claim_admitted');
    expect(a.limitation).toBe('none');
    expect(a.varied).toBe(true);
    expect(a.gridMatched).toBe(true);
    expect(a.continuous).toBe(true);
    expect(a.totalVariation).toBeGreaterThan(0);
  });

  it('withholds a constant (zero-variation) trace with no timestamp', () => {
    const a = admitENF(constantTrace, opts);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('no_drift_fingerprint');
    expect(a.varied).toBe(false);
    expect(a.totalVariation).toBe(0);
  });

  it('withholds a varied trace that does not match the grid', () => {
    // the matched trace against the well-separated G2 grid: varied but no match
    const a = admitENF(matchedTrace, { ...opts, grid: otherGrid });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('grid_mismatch');
    expect(a.varied).toBe(true);
    expect(a.gridMatched).toBe(false);
  });

  it('downgrades a matched but spliced trace to observation_only', () => {
    // splicedTrace matches its own continuous prefix grid but breaks continuity.
    // Use a grid the spliced trace matches within tolerance so only the tamper
    // gate trips it.
    const a = admitENF(splicedTrace, { grid: splicedTrace, matchTol: 0, maxStep: 3 });
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('tamper_suspected');
    expect(a.varied).toBe(true);
    expect(a.gridMatched).toBe(true);
    expect(a.continuous).toBe(false);
  });

  it('a matched, continuous trace at a looser step bound is admitted', () => {
    // splicedTrace jumps 51->70 (19) and 70->50 (20); maxStep 20 clears both,
    // so continuity holds and the matched, varied trace is admitted.
    const a = admitENF(splicedTrace, { grid: splicedTrace, matchTol: 0, maxStep: 20 });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.continuous).toBe(true);
  });
});

describe('ENFMaster (mirrors enf_master)', () => {
  it('every boundary witness holds', () => {
    expect(ENFMaster.matchedTraceVaried).toBe(true);
    expect(ENFMaster.constantTraceRejected).toBe(true);
    expect(ENFMaster.matchedTraceMatchesGrid).toBe(true);
    expect(ENFMaster.matchedTraceNotOtherGrid).toBe(true);
    expect(ENFMaster.gridsWellSeparated).toBe(true);
    expect(ENFMaster.gridRefNotFlagged).toBe(true);
    expect(ENFMaster.splicedTraceFlagged).toBe(true);
    expect(ENFMaster.certTraceVaried).toBe(true);
    expect(ENFMaster.certUniquenessRefuted).toBe(true);
    expect(ENFMaster.certTamperRejected).toBe(true);
  });

  it('the certificate records all gates', () => {
    expect(enfRusticCertificate.traceVaried).toBe(true);
    expect(enfRusticCertificate.gridMatched).toBe(true);
    expect(enfRusticCertificate.uniquenessRefuted).toBe(true);
    expect(enfRusticCertificate.continuityChecked).toBe(true);
    expect(enfRusticCertificate.tamperRejected).toBe(true);
  });
});
